import{c as a,Q as i,j as t,m as e}from "./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"AI使用文档 - Vibe Coding实战指南","description":"如何在开发中ALL IN AI，实现AI辅助编程，包括主流AI模型选择、工具集成和实战经验分享","frontmatter":{"title":"AI使用文档 - Vibe Coding实战指南","date":"2026-05-31T00:00:00.000Z","description":"如何在开发中ALL IN AI，实现AI辅助编程，包括主流AI模型选择、工具集成和实战经验分享","tags":["AI辅助编程","Vibe Coding","MCP工具","工具集成","开发效率"],"author":"一行栗子"},"headers":[],"relativePath":"blog/ai-usage-guide.md","filePath":"blog/ai-usage-guide.md","lastUpdated":1780270810000}'),o={name:"blog/ai-usage-guide.md"};function r(l, s, n, d, c, p){return i(),t("div",null,[...s[0]||(s[0]=[e(`<div class="ai-hero"><div class="ai-content"><h1 class="ai-title">🤖 AI使用文档</h1><p class="ai-subtitle"> Vibe Coding 实战指南<br> 如何在开发中 ALL IN AI，让AI成为你的开发利器 </p></div></div><h2 id="为什么需要这个文档" tabindex="-1">为什么需要这个文档？ <a class="header-anchor" href="#为什么需要这个文档" aria-label="Permalink to &quot;为什么需要这个文档？&quot;">​</a></h2><p>因为有群友反映不知道如何 ALL IN AI，或者说如何让AI嵌入开发流程，对AI的使用做到心中有数。</p><h2 id="主流ai模型介绍" tabindex="-1">主流AI模型介绍 <a class="header-anchor" href="#主流ai模型介绍" aria-label="Permalink to &quot;主流AI模型介绍&quot;">​</a></h2><div class="model-card model-free"><div class="model-header"><span class="model-icon">🇨🇳</span><h3 class="model-title">Trae CN 集成的国内模型</h3><span class="model-badge">免费使用</span></div><div class="model-desc"><p>以免费使用来引流，总结一下：<strong>拉完了，性能很一般</strong>。</p><p>目前（26年5月）勉强还可以的 GLM5.1，刚刚可以吃到 Gemini、GPT 等模型的尾气。仅此而已。</p><p style="color:#00acc1;margin-top:1rem;">✨ 优点：token便宜</p><p style="color:#f44336;">缺点：性能一般</p></div></div><div class="model-card model-paid"><div class="model-header"><span class="model-icon">🚀</span><h3 class="model-title">Trae 集成的海外模型</h3><span class="model-badge">付费使用</span></div><div class="model-desc"><p>强度都很可以，但价格不便宜。</p><p>主播之前写自己的项目喜欢用 <strong>Gemini Flash</strong>。现在公司提供的 GLM，也就换了，用起来还行，但是相较于 Gemini 还是有点距离。</p><p>但是价格摆到那，也不多说什么，平时开发也可以。</p></div></div><div class="model-card model-best"><div class="model-header"><span class="model-icon">👑</span><h3 class="model-title">Claude</h3><span class="model-badge">编程最强</span></div><div class="model-desc"><p>严格来说，目前在编程最强的还是 <strong>Claude</strong>。</p><p>但是这个对国内卡的很严，纯纯厂商脑子抽筋，不评价了。</p></div></div><h2 id="模型工具集成" tabindex="-1">模型工具集成 <a class="header-anchor" href="#模型工具集成" aria-label="Permalink to &quot;模型工具集成&quot;">​</a></h2><p>这些模型集成工具是 <strong>Trae</strong>、<strong>Cursor</strong>、<strong>Claude Code</strong> 等。</p><div class="tip custom-block"><p class="custom-block-title">商业模式</p><p>它们就是工具厂商集中统一向模型提供商购买token，所以你可以看到它们会卖月付套餐。<br><br> 你也可以自己去第三方平台（阿里云、腾讯云、火山引擎等）或者大模型官网购买token套餐，然后自定义导入。</p></div><h2 id="vibe-coding-开发流程" tabindex="-1">Vibe Coding 开发流程 <a class="header-anchor" href="#vibe-coding-开发流程" aria-label="Permalink to &quot;Vibe Coding 开发流程&quot;">​</a></h2><p>主播讲一下现在 Vibe Coding 都是怎么做的。</p><h3 id="后端开发" tabindex="-1">后端开发 <a class="header-anchor" href="#后端开发" aria-label="Permalink to &quot;后端开发&quot;">​</a></h3><div class="practice-card"><h3 class="practice-title"><span class="step-number">1</span> 接口文档同步 </h3><p>通过 Swagger 注解，AI可以直接查看接口定义。</p><p>再通过 IDEA 的 <strong>ApiFox插件</strong>进行远程同步 ApiFox上面的项目。</p><p>这样AI修改你的接口，就可以很简单的实现接口文档同步。</p><div class="code-block"><span class="comment">// IDEA插件市场搜索</span><span class="keyword">Apifox</span> - API 文档工具 <pre><code>&lt;span class=&quot;comment&quot;&gt;// 操作步骤&lt;/span&gt;
1. 在 ApiFox 中新建授权秘钥
2. 在插件里连接到你的 ApiFox 账号
3. 在 ApiFox 里新建项目，选择这个项目
4. 点击左边的按钮，进行项目扫描
5. 点击同步按钮，直接就可以进行接口文档同步
</code></pre></div></div><div class="practice-card"><h3 class="practice-title"><span class="step-number">2</span> 数据库操作 </h3><p>常见问题：你根据业务自己修改了数据库表结构（通过 DataGrip）。</p><p>最淳朴的方式：从 DataGrip 进行表结构导出。</p><p>但是AI在写业务的时候，也没办法直接修改数据库，只能给你说，然后你还需要自己改，很麻烦。</p><div class="tip-box"><div class="tip-title">💡 MCP 工具解决方案</div><p>在 Trae 这种 IDE 里，是可以在自己的环境里面配置模型调用的 <strong>MCP 工具</strong>的。</p><p style="margin-top:1rem;"><strong>MCP（Model Context Protocol）</strong>：AI调用工具链来实现和第三方中间件交互。</p></div></div><h2 id="mcp-工具集成" tabindex="-1">MCP 工具集成 <a class="header-anchor" href="#mcp-工具集成" aria-label="Permalink to &quot;MCP 工具集成&quot;">​</a></h2><p>通过 MCP，AI可以随时读取或者修改数据库。</p><div class="warning custom-block"><p class="custom-block-title">安全性</p><p>可以选择赋予读或者写权限来保证数据操作安全。</p></div><div class="tip custom-block"><p class="custom-block-title">优势</p><p>相比在终端通过命令行操作，MCP有两个优点：</p><ol><li><strong>速度快</strong></li><li><strong>省 token</strong></li></ol></div><h3 id="mcp-集成流程" tabindex="-1">MCP 集成流程 <a class="header-anchor" href="#mcp-集成流程" aria-label="Permalink to &quot;MCP 集成流程&quot;">​</a></h3><div class="mcp-flow"><div class="mcp-node"><div style="font-size:1.5rem;margin-bottom:0.5rem;">⚙️</div><div style="font-weight:600;">MCP 市场</div><div style="font-size:0.875rem;color:rgba(255, 255, 255, 0.85);">下载数据库MCP</div></div><span class="mcp-arrow">→</span><div class="mcp-node"><div style="font-size:1.5rem;margin-bottom:0.5rem;">🔧</div><div style="font-weight:600;">配置</div><div style="font-size:0.875rem;color:rgba(255, 255, 255, 0.85);">导入JSON连接</div></div><span class="mcp-arrow">→</span><div class="mcp-node"><div style="font-size:1.5rem;margin-bottom:0.5rem;">🔗</div><div style="font-weight:600;">数据库连接</div><div style="font-size:0.875rem;color:rgba(255, 255, 255, 0.85);">读/写权限</div></div><span class="mcp-arrow">→</span><div class="mcp-node"><div style="font-size:1.5rem;margin-bottom:0.5rem;">🤖</div><div style="font-weight:600;">AI 操作</div><div style="font-size:0.875rem;color:rgba(255, 255, 255, 0.85);">实时读写</div></div></div><h3 id="trae-mcp-配置步骤" tabindex="-1">Trae MCP 配置步骤 <a class="header-anchor" href="#trae-mcp-配置步骤" aria-label="Permalink to &quot;Trae MCP 配置步骤&quot;">​</a></h3><div class="practice-card"><h3 class="practice-title">📝 MCP 配置教程</h3><ol style="line-height:2;padding-left:1.5rem;"><li>点击 <strong>设置</strong></li><li>找到 <strong>MCP</strong> 选项</li><li>点击 <strong>添加</strong>，然后从市场上下载即可</li><li>配置只需要一个 <strong>JSON 文件</strong>就行</li><li>直接把数据库连接发给AI，AI给你写好JSON代码，你导入即可</li></ol><div class="code-block"><span class="comment">// 数据库MCP配置示例</span> { <span class="string">&quot;mcpServers&quot;</span>: { <span class="string">&quot;database&quot;</span>: { <span class="string">&quot;command&quot;</span>: <span class="string">&quot;npx&quot;</span>, <span class="string">&quot;args&quot;</span>: [<span class="string">&quot;-y&quot;</span>, <span class="string">&quot;@modelcontextprotocol/server-sqlite&quot;</span>], <span class="string">&quot;database&quot;</span>: <span class="string">&quot;./my-project.db&quot;</span> } } } </div><p style="margin-top:1rem;color:#666;"> 💡 <strong>提示</strong>：MCP可以设置为项目级，保证在不同项目之间MCP不冲突。 </p></div><div class="tip custom-block"><p class="custom-block-title">MCP 生态</p><p>MCP就是AI模型连接外部工具获取数据、修改数据，所以MCP这么大的市场，都是可以自己摸索着玩的。</p></div><h2 id="项目规则和速览" tabindex="-1">项目规则和速览 <a class="header-anchor" href="#项目规则和速览" aria-label="Permalink to &quot;项目规则和速览&quot;">​</a></h2><div class="tool-integration"><div class="integration-card"><div class="integration-title">📋 项目规则</div><div class="integration-desc"> 关于一些规范<br><br> 比如你想让AI按照你的模块规划进行新的业务模块编写，或者按照你的编码风格（例如必须加注释等）。 </div></div><div class="integration-card"><div class="integration-title">👁️ 项目速览</div><div class="integration-desc"> 关于项目的结构和必要的通用组件说明<br><br> 方便AI在新的对话中可以快速理解项目，然后着手自己的模块开发。 </div></div></div><div class="tip custom-block"><p class="custom-block-title">最佳实践</p><p>当AI在这次会话结束时，让它补充有必要的部分到文件中。这样每次新会话都能快速上手项目。</p></div><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div class="summary-section"><h2 class="summary-title">🎯 Vibe Coding 核心要点</h2><div class="summary-item"> ✅ <strong>模型选择</strong>：根据预算和需求选择合适的AI模型 </div><div class="summary-item"> ✅ <strong>工具集成</strong>：通过 MCP 让AI连接各种开发工具 </div><div class="summary-item"> ✅ <strong>接口同步</strong>：使用 ApiFox + IDEA插件实现文档自动同步 </div><div class="summary-item"> ✅ <strong>项目规则</strong>：建立清晰的项目规范和速览文档 </div><div class="summary-item"> ✅ <strong>实践驱动</strong>：让AI根据实际业务需求学习和调整 </div><p style="margin-top:2rem;opacity:0.9;font-size:1.1rem;"> Vibe Coding 就是让AI成为你的开发助手，而不是替代你的思考。<br> 工具只是手段，真正的核心还是你的业务理解和技术判断力。 </p></div><hr><p><strong>作者</strong>：一行栗子 | <strong>标签</strong>：AI辅助编程 · Vibe Coding · MCP工具 · 开发效率 · 工具集成</p><div style="background:#f8f9fa;padding:1.5rem;border-radius:0.8rem;margin-top:2rem;text-align:center;"><p style="color:#666;margin:0;"> 💡 <strong>提示</strong>：AI是强大的工具，但最好的使用方式是让它辅助你的工作，而不是完全依赖它。 </p></div>`,32)])])}const v=a(o,[["render",r]]);export{g as __pageData,v as default};
